import sys
from typing import List, Optional

class TreeNode:
    def __init__(self, val: int):
        self.val = val
        self.left: Optional['TreeNode'] = None
        self.right: Optional['TreeNode'] = None

class Solution:
    def distanceK(self, root: Optional[TreeNode], target: int, K: int) -> List[int]:
        if not root:
            return []
        # Build adjacency list
        adj = {}
        def add_edge(u: int, v: int):
            adj.setdefault(u, []).append(v)
            adj.setdefault(v, []).append(u)
        def dfs(node: Optional[TreeNode]):
            if not node:
                return
            if node.left:
                add_edge(node.val, node.left.val)
                dfs(node.left)
            if node.right:
                add_edge(node.val, node.right.val)
                dfs(node.right)
        dfs(root)
        # BFS from target
        from collections import deque
        q = deque([(target, 0)])
        visited = {target}
        res = []
        while q:
            node, d = q.popleft()
            if d == K:
                res.append(node)
            if d > K:
                continue
            for nb in adj.get(node, []):
                if nb not in visited:
                    visited.add(nb)
                    q.append((nb, d + 1))
        if not res:
            return [-1]
        return sorted(res)

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    N = int(next(it))
    nodes = {}
    children = set()
    for _ in range(N):
        val = int(next(it))
        left = int(next(it))
        right = int(next(it))
        if val not in nodes:
            nodes[val] = TreeNode(val)
        cur = nodes[val]
        if left != -1:
            if left not in nodes:
                nodes[left] = TreeNode(left)
            cur.left = nodes[left]
            children.add(left)
        if right != -1:
            if right not in nodes:
                nodes[right] = TreeNode(right)
            cur.right = nodes[right]
            children.add(right)
    # root is the node not appearing as child
    root_val = (set(nodes.keys()) - children).pop()
    root = nodes[root_val]
    target = int(next(it))
    K = int(next(it))
    sol = Solution()
    ans = sol.distanceK(root, target, K)
    print(' '.join(map(str, ans)))

