#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<int> distanceK(TreeNode* root, int target, int K) {
        if (!root) return {};
        unordered_map<int, vector<int>> adj;
        function<void(TreeNode*)> dfs = [&](TreeNode* node) {
            if (!node) return;
            if (node->left) {
                adj[node->val].push_back(node->left->val);
                adj[node->left->val].push_back(node->val);
                dfs(node->left);
            }
            if (node->right) {
                adj[node->val].push_back(node->right->val);
                adj[node->right->val].push_back(node->val);
                dfs(node->right);
            }
        };
        dfs(root);
        queue<pair<int,int>> q;
        unordered_set<int> visited;
        q.push({target,0});
        visited.insert(target);
        vector<int> res;
        while(!q.empty()){
            auto _tmp_binding_0 = q.front(); auto node = _tmp_binding_0.first; auto d = _tmp_binding_0.second; q.pop();
            if (d == K) res.push_back(node);
            if (d > K) continue;
            for(int nb: adj[node]){
                if (!visited.count(nb)){
                    visited.insert(nb);
                    q.push({nb, d+1});
                }
            }
        }
        if (res.empty()) return {-1};
        sort(res.begin(), res.end());
        return res;
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    if(!(cin>>N)) return 0;
    unordered_map<int, TreeNode*> nodes;
    unordered_set<int> childVals;
    for(int i=0;i<N;++i){
        int val,left,right;cin>>val>>left>>right;
        if(nodes.find(val)==nodes.end()) nodes[val]=new TreeNode(val);
        TreeNode* cur=nodes[val];
        if(left!=-1){
            if(nodes.find(left)==nodes.end()) nodes[left]=new TreeNode(left);
            cur->left=nodes[left];
            childVals.insert(left);
        }
        if(right!=-1){
            if(nodes.find(right)==nodes.end()) nodes[right]=new TreeNode(right);
            cur->right=nodes[right];
            childVals.insert(right);
        }
    }
    int rootVal=0;
    for(const auto& p:nodes){
        if(childVals.find(p.first)==childVals.end()){
            rootVal=p.first;break;
        }
    }
    TreeNode* root=nodes[rootVal];
    int target,K;cin>>target>>K;
    Solution sol;
    vector<int> ans=sol.distanceK(root,target,K);
    for(size_t i=0;i<ans.size();++i){
        if(i) cout<<' ';
        cout<<ans[i];
    }
    cout<<"\n";
    return 0;
}
